/// Build extended vocabulary (~20K entries)
/// Includes base vocab + extended entries
pub fn build_vocab_large() -> Vec<VocabEntry> {
    let mut vocab = build_vocab();
    let initial = vocab.len();

    for &(surface, reading, pos_code, cat_code) in EXTENDED_DATA {
        let pos = match pos_code {
            0 => Pos::Noun,
            1 => Pos::Verb,
            2 => Pos::IAdjective,
            3 => Pos::Adverb,
            _ => Pos::Noun,
        };
        let category = CATEGORIES[cat_code as usize];
        vocab.push(VocabEntry::new(surface, reading, pos, category));
    }

    eprintln!("  vocab_large: {} base + {} extended = {} total",
        initial, EXTENDED_DATA.len(), vocab.len());
    vocab
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_vocab_large_count() {
        let vocab = build_vocab_large();
        assert!(vocab.len() > 15000, "Expected >15K entries, got {}", vocab.len());
    }

    #[test]
    fn test_has_verbs() {
        let vocab = build_vocab_large();
        let verb_count = vocab.iter().filter(|e| matches!(e.pos, Pos::Verb)).count();
        assert!(verb_count > 200, "Expected >200 verbs, got {}", verb_count);
    }

    #[test]
    fn test_has_adjectives() {
        let vocab = build_vocab_large();
        let adj_count = vocab.iter().filter(|e| matches!(e.pos, Pos::IAdjective)).count();
        assert!(adj_count > 50, "Expected >50 adjectives, got {}", adj_count);
    }
}